Downloading 2024 Data
We repeat the same procedure used in earlier chapters to fetch the 2024 FH‑VHV trip records from the NYC TLC website. The data are stored in Parquet format and are loaded into our DuckDB database as a new table NycTrips2024.

SourcePage &lt;- rvest::read_html(
  "https://www.nyc.gov/site/tlc/about/tlc-trip-record-data.page"
)

TripLinks &lt;-
  SourcePage |&gt;
  rvest::html_elements(xpath = '//div[@class="faq-answers"]//li/a') |&gt;
  rvest::html_attr("href") |&gt;
  grep(pattern = "fhvhv_[a-z]+_2024-\\d{2}\\.parquet", value = TRUE) |&gt;
  trimws() |&gt;
  sort()

FileNames &lt;- basename(TripLinks)

ParquetFolderPath &lt;- file.path(BigFilesPath, "trip-data")

YearFoldersPath &lt;-
  gsub(
    x = FileNames,
    pattern = "^fhvhv_tripdata_|-\\d{2}\\.parquet$",
    replacement = ""
  ) |&gt;
  paste0("year=", a = _) |&gt;
  unique() |&gt;
  file.path(ParquetFolderPath, a = _)

MonthFoldersPath &lt;-
  paste(
    gsub(
      x = FileNames,
      pattern = "^fhvhv_tripdata_|-\\d{2}\\.parquet$",
      replacement = ""
    ) |&gt;
      paste0("year=", a = _),
    gsub(
      x = FileNames,
      pattern = "^fhvhv_tripdata_\\d{4}-|\\.parquet$",
      replacement = ""
    ) |&gt;
      paste0("month=", a = _),
    sep = "/"
  ) |&gt;
  file.path(ParquetFolderPath, a = _) |&gt;
  sort()

FoldersToCreate &lt;- c(
  BigFilesPath,
  ParquetFolderPath,
  YearFoldersPath,
  MonthFoldersPath
)

for (paths in FoldersToCreate) {
  if (!file.exists(paths)) dir.create(paths)
}

options(timeout = 1800)

# Parquet trip data
for (link_i in seq_along(TripLinks)) {
  download.file(
    TripLinks[link_i],
    destfile = file.path(MonthFoldersPath[link_i], "part-0.parquet"),
    mode = "wb"
  )
}

ParquetSource &lt;-
  file.path(MonthFoldersPath, "part-0.parquet") |&gt;
  paste0("'", a = _, "'") |&gt;
  paste0(collapse = ", ") |&gt;
  paste0("read_parquet([", a = _, "])")


con &lt;- DBI::dbConnect(
  duckdb::duckdb(),
  dbdir = file.path(BigFilesPath, "my-db.duckdb")
)

NycTripsCreateTable &lt;- glue::glue_safe(
  "
CREATE TABLE NycTrips2024 AS
    SELECT 
        ROW_NUMBER() OVER () AS trip_id,
        *,
        (driver_pay + tips) / (trip_time / 3600) AS performance_per_hour
    FROM {ParquetSource}
"
)

DBI::dbExecute(con, NycTripsCreateTable)

DBI::dbDisconnect(con, shutdown = TRUE)

rm(con)
